package com.hospital.management.model;
/** String-backed medical-record form. Patient and doctor identities are derived from the appointment. */
public class MedicalRecordForm {private Long medicalRecordId,appointmentId;private String symptoms,diagnosis,treatmentNotes,allergies,bloodPressure,temperature,weight,height;public Long getMedicalRecordId(){return medicalRecordId;}public void setMedicalRecordId(Long v){medicalRecordId=v;}public Long getAppointmentId(){return appointmentId;}public void setAppointmentId(Long v){appointmentId=v;}public String getSymptoms(){return symptoms;}public void setSymptoms(String v){symptoms=v;}public String getDiagnosis(){return diagnosis;}public void setDiagnosis(String v){diagnosis=v;}public String getTreatmentNotes(){return treatmentNotes;}public void setTreatmentNotes(String v){treatmentNotes=v;}public String getAllergies(){return allergies;}public void setAllergies(String v){allergies=v;}public String getBloodPressure(){return bloodPressure;}public void setBloodPressure(String v){bloodPressure=v;}public String getTemperature(){return temperature;}public void setTemperature(String v){temperature=v;}public String getWeight(){return weight;}public void setWeight(String v){weight=v;}public String getHeight(){return height;}public void setHeight(String v){height=v;}}
